import React, { useEffect, useRef, useState } from "react";
import { Rocket, Eye, History, Telescope, ChevronRight, ArrowRightToLine, Mountain, BookOpen } from "lucide-react";

// Constantes de datos con iconos
const mainSections = [
  {
    id: "objective",
    title: "OBJETIVO",
    displayTitle: "Objetivo",
    icon: ArrowRightToLine,
    body: ( 
      <p> 
        Preservamos, organizamos y exhibimos el patrimonio corporativo de empresas bolivianas con más de 40 años de trayectoria. 
        Digitalizamos archivos, certificamos hitos históricos y creamos narrativas vivas que honran el legado mientras inspiran 
        a la próxima generación de líderes empresariales. 
      </p> 
    ),
    image: '/media/historiapage/bolivia.jpg', 
  },
  {
    id: "mission",
    title: "MISIÓN",
    displayTitle: "Misión",
    icon: Mountain,
    body: ( 
      <p> 
        Proteger la memoria de la empresa boliviana mediante documentación rigurosa, narrativas históricas cuidadosas y diseño atemporal, 
        haciendo que el viaje de cada empresa sea accesible, verificable y bellamente preservado para el futuro. 
      </p> 
    ),
    image: '/media/historiapage/AGRO.jpg',
  },
  {
    id: "vision",
    title: "VISIÓN",
    displayTitle: "Visión",
    icon: Eye,
    body: ( 
      <p> 
        Un archivo nacional prestigioso donde la historia de la excelencia empresarial sea atesorada, sirviendo como referencia para 
        investigadores, emprendedores y familias que elevan el legado de la industria boliviana en el escenario mundial. 
      </p> 
    ),
    image: '/media/historiapage/flamingob.jpg',
  },
  {
    id: "origin",
    title: "ORIGEN",
    displayTitle: "Origen",
    icon: History,
    body: ( 
      <p> 
        Nacidos del compromiso con la memoria cultural, surgimos cuando historiadores, archiveros e innovadores se unieron alrededor 
        de una idea simple: si no documentamos nuestras empresas hoy, las generaciones futuras heredarán silencio donde debería haber legado. 
      </p> 
    ),
    image: '/media/historiapage/salarB.jpg', 
  },
];

const howItStartedSection = {
  id: "how",
  title: "NUESTRA HISTORIA",
  displayTitle: "Nuestra Historia",
  icon: BookOpen,
  body: (
    <div className="w-full">
      <div className="relative py-1.5rem px-1rem md:px-0">
        <div className="hidden md:block absolute left-0 right-0 top-2.5rem h-0.1rem bg-white" />
        <div className="block md:hidden absolute left-1.5rem top-1.5rem bottom-0 w-0.1rem bg-gradient-to-b from-transparent via-[#072D42]/20 to-transparent" />
        <ol className="relative z-10 flex flex-col md:flex-row gap-3rem md:gap-2.5rem lg:gap-4rem">
          {[
            { year: "1980s", text: "Primeros archivos fundacionales recolectados en diversos sectores empresariales." },
            { year: "1990s", text: "Primeras alianzas público-privadas para la preservación histórica." },
            { year: "2000s", text: "Programa de digitalización y establecimiento de estándares de certificación." },
            { year: "Actualidad", text: "Una plataforma viva que conecta el legado con la innovación empresarial." },
          ].map((m) => (
            <li key={m.year} className="md:min-w-[10rem] md:text-center">
              <div className="hidden md:flex flex-col items-center gap-0.75rem">
                <div className="relative">
                  <span className="block w-0.75rem h-0.75rem rounded-full border-0.1rem border-[#072D42]" />
                </div>
                <div className="text-0.9rem font-light tracking-wide">
                  <span className="font-serif text-1.1rem block mb-0.25rem text-[#072D42]">{m.year}</span>
                  <span className="block max-w-[16rem] text-0.8rem leading-tight text-[#072D42]/80">{m.text}</span>
                </div>
              </div>
              <div className="flex md:hidden items-start gap-1rem">
                <div className="relative pt-0.4rem">
                  <span className="block w-0.75rem h-0.75rem rounded-full border-0.1rem border-[#072D42]" />
                </div>
                <div className="text-0.9rem font-light tracking-wide">
                  <span className="font-serif text-1.1rem block mb-0.25rem text-[#072D42]">{m.year}</span>
                  <span className="block text-0.8rem leading-tight text-[#072D42]/80">{m.text}</span>
                </div>
              </div>
            </li>
          ))}
        </ol>
      </div>
    </div>
  ),
};

const allSections = [...mainSections, howItStartedSection];
const SCROLL_OFFSET = 9.375;

// Estilos de fuentes
const fontStyles = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,500;0,600;0,700;1,400&family=Montserrat:ital,wght@0,100;0,200;0,300;0,400;0,500;0,600;0,700;1,100;1,200;1,300;1,400&family=Inter:wght@100;200;300;400;500;600;700&display=swap');
  
  .font-playfair {
    font-family: 'Playfair Display', serif;
  }
  
  .font-montserrat {
    font-family: 'Montserrat', sans-serif;
  }
  
  .font-inter {
    font-family: 'Inter', sans-serif;
  }

  /* Estilos base para mejorar la responsividad */
  html {
    font-size: 16px;
  }

  @media (max-width: 768px) {
    html {
      font-size: 14px;
    }
  }

  @media (max-width: 480px) {
    html {
      font-size: 12px;
    }
  }
`;

const AboutUsPage = () => {
  const [active, setActive] = useState(allSections[0].id);
  const [revealedSections, setRevealedSections] = useState({});
  const sectionRefs = useRef({});
  const [isHeaderShrunk, setIsHeaderShrunk] = useState(false);
  const [scrollY, setScrollY] = useState(0);
  const tickingRef = useRef(false);

  // Insertar estilos en el head del documento
  useEffect(() => {
    const styleElement = document.createElement('style');
    styleElement.textContent = fontStyles;
    document.head.appendChild(styleElement);
    
    return () => {
      document.head.removeChild(styleElement);
    };
  }, []);

  // ⚡ OPTIMIZADO: Scroll con throttling
  useEffect(() => {
    const handleScroll = () => {
      setIsHeaderShrunk(window.scrollY > 100);
      
      if (!tickingRef.current) {
        requestAnimationFrame(() => {
          setScrollY(window.scrollY);
          tickingRef.current = false;
        });
        tickingRef.current = true;
      }
    };
    
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // ⚡ OPTIMIZADO: IntersectionObserver más eficiente
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            setActive(entry.target.id);
            setRevealedSections(prev => ({ ...prev, [entry.target.id]: true }));
          }
        });
      },
      { 
        root: null, 
        threshold: 0.3,
        rootMargin: "-10% 0px -10% 0px"
      },
    );

    allSections.forEach((s) => {
      const el = sectionRefs.current[s.id];
      if (el) observer.observe(el);
    });
    
    return () => observer.disconnect();
  }, []);

  const scrollTo = (e, id) => {
    e.preventDefault();
    const el = sectionRefs.current[id];
    if (!el) return;
    
    const elementPosition = el.getBoundingClientRect().top + window.scrollY;
    const offsetPosition = elementPosition - (SCROLL_OFFSET * 16);
    
    window.scrollTo({ top: offsetPosition, behavior: "smooth" });
    setActive(id);
  };

  const parallaxStyle = {
    transform: `translate3d(0, ${scrollY * 0.4}px, 0)`
  };

  // Componente para el icono de fondo a la derecha (solo para mainSections)
  const BackgroundIcon = ({ icon: Icon, className = "" }) => {
    return (
      <div className={`absolute right-1rem top-1/2 -translate-y-1/2 flex items-center justify-center pointer-events-none ${className}`}>
        <Icon className="w-8rem h-8rem md:w-12rem md:h-12rem opacity-10 text-[#072D42] group-hover:text-white transition-colors duration-500" />
      </div>
    );
  };

  return (
    <div className="bg-[#FAF8F5] text-[#072D42] min-h-screen font-sans [&_a]:no-underline [&_a:hover]:no-underline text-base">
      {/* HEADER CON EFECTO PARALLAX OPTIMIZADO */}
      <div className="h-[20vh] min-h-[15rem] max-h-[30rem] mb-5rem overflow-hidden relative">
        <header className="relative h-full">
          <div 
            className="absolute inset-0 w-full h-full"
            style={parallaxStyle}
          >
            <img 
              src="/media/historiapage/salarB.jpg"
              alt="Fondo del Archivo Histórico Empresarial Boliviano"
              className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-black/45"></div>
          </div>
          
          <div className="relative z-30 p-5rem lg:p-12rem text-white h-full flex flex-col justify-center">
            {/* TÍTULO PRINCIPAL CON FUENTE ELEGANTE */}
            <h1 className="font-playfair text-3rem lg:text-6rem font-normal leading-[0.9] tracking-tight mb-2rem text-white">
              Nosotros
            </h1>
            
            {/* SUBTÍTULO CON FUENTE EMPRESARIAL */}
            <div className="mb-3rem">
              <h2 className="font-montserrat text-1.5rem lg:text-1.8rem font-light tracking-[0.2em] uppercase text-white/95 mb-1.5rem">
                Archivo Histórico Empresarial
              </h2>
              <div className="h-0.1rem w-8rem bg-white/70 mb-2rem"></div>
            </div>
            
            {/* TEXTO DESCRIPTIVO CON FUENTE MODERNA */}
            <p className="font-inter text-1.2rem lg:text-1.5rem font-extralight tracking-wide max-w-50rem text-white/90 leading-relaxed">
              Registrando la evolución del sector empresarial boliviano y preservando legados de más de 40 años.
            </p>
          </div>
        </header>
      </div>

      <main className="px-2.5rem py-0">
        {/* NAVEGACIÓN MÓVIL - SOLO EN MÓVIL */}
        <div className="block lg:hidden mb-4rem">
          <nav className="flex flex-row gap-1rem overflow-x-auto py-2rem">
            {allSections.map((s) => (
              <a
                key={s.id}
                href={`#${s.id}`}
                onClick={(e) => scrollTo(e, s.id)}
                className={`
                  relative text-left py-1.5rem px-2rem transition-colors duration-200 whitespace-nowrap
                  rounded-0.5rem border border-[#9298A6]/30 bg-white/10
                  hover:bg-[#9298A6]/10
                  ${
                    active === s.id 
                      ? 'bg-[#9298A6]/20 font-medium'
                      : 'font-light opacity-80 hover:opacity-100'
                  }
                `}
              >
                <span className="tracking-widest text-0.9rem text-[#072D42]">{s.title}</span>
              </a>
            ))}
          </nav>
        </div>

        <div className="flex flex-col lg:flex-row gap-8rem lg:items-start">
          {/* ASIDE IZQUIERDO - SOLO EN DESKTOP */}
          <aside className="hidden lg:block lg:w-1/6 sticky top-10rem">
            <nav className="flex lg:flex-col gap-0 rounded-0.5rem overflow-hidden border border-[#9298A6]/30 bg-white/10">
              {allSections.map((s) => (
                <a
                  key={s.id}
                  href={`#${s.id}`}
                  onClick={(e) => scrollTo(e, s.id)}
                  className={`
                    relative group flex items-center justify-between py-1.5rem px-2rem transition-all duration-300
                    after:content-[''] after:absolute after:left-0 after:bottom-0
                    after:w-full after:h-0.1rem after:bg-[#9298A6]
                    after:origin-center after:transition-transform after:duration-300 after:ease-out
                    border-b border-[#9298A6]/20 last:border-b-0
                    hover:bg-[#9298A6]/10
                    ${
                      active === s.id 
                        ? 'font-semibold opacity-100 after:scale-x-100 bg-[#9298A6]/20'
                        : 'font-extralight opacity-70 hover:opacity-100 after:scale-x-0 hover:after:scale-x-100'
                    }
                  `}
                >
                  <div className="flex items-center gap-1.5rem">
                    <s.icon className="w-1.5rem h-1.5rem text-[#072D42] opacity-70 group-hover:opacity-100 transition-opacity duration-300" />
                    <span className={`
                      tracking-widest text-0.9rem text-[#072D42] font-montserrat
                      ${active === s.id ? 'font-semibold' : 'font-extralight'}
                    `}>
                      {s.title}
                    </span>
                  </div>
                  <div className="opacity-0 group-hover:opacity-100 transition-all duration-300 transform translate-x-0.5rem group-hover:translate-x-0">
                    <ChevronRight className="w-1.2rem h-1.2rem text-[#072D42]" />
                  </div>
                </a>
              ))}
            </nav>
          </aside>

          {/* CONTENIDO PRINCIPAL */}
          <section className="w-full lg:w-4/6 flex flex-col gap-10rem">
            {mainSections.map((s) => (
              <div
                key={s.id}
                id={s.id}
                ref={(el) => (sectionRefs.current[s.id] = el)}
                className={`
                  scroll-mt-6rem bg-white rounded-1rem shadow-md border border-[#072D42]/20 hover:border-[#072D42] hover:shadow-lg 
                  overflow-hidden group hover:bg-[#072D42]
                  transform transition-all duration-500 ease-out relative
                  ${revealedSections[s.id] ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-2rem'}
                `}
              >
                <BackgroundIcon icon={s.icon} />
                
                <div className={`transition-opacity duration-300 relative z-10 ${active === s.id ? "opacity-100" : "opacity-80"}`}>
                  <div className="flex flex-col md:flex-row">
                    {s.image && (
                      <div className="md:w-[35%] flex order-1 md:order-1 overflow-hidden">
                        <img 
                          src={s.image} 
                          alt={s.displayTitle} 
                          className="w-full h-full object-cover rounded-l-1rem md:rounded-r-none transform group-hover:scale-105 transition-transform duration-700 ease-out" 
                        />
                      </div>
                    )}
                    
                    <div className={s.image ? 'md:w-[65%] order-2 md:order-2 p-4rem md:p-6rem lg:p-8rem text-center md:text-left relative z-20' : 'w-full order-2 p-4rem md:p-6rem lg:p-8rem text-center md:text-left relative z-20'}>
                      <div className="mb-4rem flex flex-col items-center md:items-start overflow-hidden">
                        <div className="flex items-center gap-1.5rem mb-2rem flex-col md:flex-row w-full">
                          <s.icon className="w-2.5rem h-2.5rem text-[#072D42] group-hover:text-white transition-all duration-500 ease-out transform group-hover:scale-110 flex-shrink-0" />
                          <h2 className="font-playfair text-2rem lg:text-2.5rem font-normal tracking-wide text-[#072D42] group-hover:text-white transition-all duration-500 ease-out transform translate-y-0 group-hover:-translate-y-0.5rem">
                            {s.displayTitle}
                          </h2>
                        </div>
                        <div className="h-0.1rem w-5rem bg-[#072D42] group-hover:bg-white transition-all duration-500 ease-out transform origin-left md:ml-4.5rem mx-auto md:mx-0 group-hover:scale-x-150"></div>
                      </div>
                      <div className="font-inter text-1.1rem leading-relaxed font-light tracking-wide text-[#072D42]/95 group-hover:text-white/95 transition-all duration-700 ease-out transform translate-x-0 group-hover:translate-x-1rem max-w-prose mx-auto md:mx-0 text-justify md:text-left relative z-30">
                        {s.body}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            ))}
            
            {/* Sección "Nuestra Historia" */}
            <div 
              id={howItStartedSection.id}
              ref={(el) => (sectionRefs.current[howItStartedSection.id] = el)}
              className={`
                scroll-mt-6rem 
                transform transition-all duration-700 ease-out
                ${revealedSections[howItStartedSection.id] ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-2rem'}
              `}
            >
              <div className="mb-4rem text-center md:text-left">
                <div className="flex items-center gap-1.5rem mb-2rem flex-col md:flex-row justify-center md:justify-start">
                  <howItStartedSection.icon className="w-2.5rem h-2.5rem text-[#072D42]" />
                  <h2 className="font-playfair text-2rem lg:text-2.5rem font-normal tracking-wide text-[#072D42]">
                    {howItStartedSection.displayTitle}
                  </h2>
                </div>
                <div className="h-0.1rem w-5rem bg-[#072D42] mx-auto md:ml-4.5rem"></div>
              </div>
              <div className="font-inter text-justify md:text-left">
                {howItStartedSection.body}
              </div>
            </div>
          </section>

          {/* ASIDE DERECHO - SOLO EN DESKTOP */}
          <aside className="hidden lg:block lg:w-1/6 sticky top-10rem">
            <nav className="flex lg:flex-col gap-0 rounded-0.5rem overflow-hidden border border-[#9298A6]/30 bg-white/10">
              {allSections.map((s) => (
                <a
                  key={s.id}
                  href={`#${s.id}`}
                  onClick={(e) => scrollTo(e, s.id)}
                  className={`
                    relative group flex items-center justify-between py-1.5rem px-2rem transition-all duration-300
                    after:content-[''] after:absolute after:left-0 after:bottom-0
                    after:w-full after:h-0.1rem after:bg-[#9298A6]
                    after:origin-center after:transition-transform after:duration-300 after:ease-out
                    border-b border-[#9298A6]/20 last:border-b-0
                    hover:bg-[#9298A6]/10
                    ${
                      active === s.id 
                        ? 'font-semibold opacity-100 after:scale-x-100 bg-[#9298A6]/20'
                        : 'font-extralight opacity-70 hover:opacity-100 after:scale-x-0 hover:after:scale-x-100'
                    }
                  `}
                >
                  <div className="flex items-center gap-1.5rem">
                    <s.icon className="w-1.5rem h-1.5rem text-[#072D42] opacity-70 group-hover:opacity-100 transition-opacity duration-300" />
                    <span className={`
                      tracking-widest text-0.9rem text-[#072D42] font-montserrat
                      ${active === s.id ? 'font-semibold' : 'font-extralight'}
                    `}>
                      {s.title}
                    </span>
                  </div>
                  <div className="opacity-0 group-hover:opacity-100 transition-all duration-300 transform translate-x-0.5rem group-hover:translate-x-0">
                    <ChevronRight className="w-1.2rem h-1.2rem text-[#072D42]" />
                  </div>
                </a>
              ))}
            </nav>
          </aside>
        </div>

        <footer className="mt-12rem pt-4rem border-t border-[#072D42]/20 text-center max-w-50rem mx-auto">
          <p className="text-0.9rem font-light tracking-wide text-[#072D42]/60 font-montserrat">
            © {new Date().getFullYear()} Archivo Histórico Empresarial Boliviano
          </p>
        </footer>
      </main>
    </div>
  );
};

export default AboutUsPage;
